def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    max_count = max(word_count.values())
    common_words = [word for word, count in word_count.items() if count == max_count]

    return sorted(common_words)[0]

# Edge case: The function returns an empty string when the input is an empty string.
